def solve(n: int, edges: list[list[int]], k: int) -> int:
    edges.sort(key=lambda x: x[2])
    if not edges:
        return 0
    max_time = edges[-1][2]

    def is_possible(t):
        parent = list(range(n))

        def find(u):
            while parent[u] != u:
                parent[u] = parent[parent[u]]
                u = parent[u]
            return u

        def union(u, v):
            u_root = find(u)
            v_root = find(v)
            if u_root != v_root:
                parent[v_root] = u_root

        for u, v, time in edges:
            if time > t:
                union(u, v)

        components = set()
        for i in range(n):
            components.add(find(i))
        return len(components) >= k

    low = 0
    high = max_time
    answer = max_time
    while low <= high:
        mid = (low + high) // 2
        if is_possible(mid):
            answer = mid
            high = mid - 1
        else:
            low = mid + 1
    return answer
